from dataclasses import dataclass
from typing import Literal

DependencyType = Literal["blocking", "enabling", "learning"]

@dataclass
class RoadmapDependency:
    predecessor_item_id: str
    successor_item_id: str
    dependency_type: DependencyType
    notes: str = ""

def find_sequencing_violations(
    roadmap: MultiQuarterRoadmap,
    dependencies: list[RoadmapDependency],
) -> list[str]:
    """
    Return list of violations where a successor is planned before its predecessor.
    Quarters are compared lexicographically: '2026-Q1' < '2026-Q2'.
    """
    item_by_id = {i.item_id: i for i in roadmap.items}
    violations = []
    for dep in dependencies:
        if dep.dependency_type != "blocking":
            continue
        pred = item_by_id.get(dep.predecessor_item_id)
        succ = item_by_id.get(dep.successor_item_id)
        if pred is None or succ is None:
            violations.append(f"MISSING_ITEM in dependency: {dep.predecessor_item_id} → {dep.successor_item_id}")
            continue
        if succ.quarter <= pred.quarter:
            violations.append(
                f"SEQUENCING_VIOLATION: '{succ.item_id}' ({succ.quarter}) "
                f"must come AFTER '{pred.item_id}' ({pred.quarter})"
            )
    return violations

from dataclasses import dataclass

TSHIRT_TO_PW = {"XS": 1, "S": 3, "M": 6, "L": 12, "XL": 20}

@dataclass
class RoadmapItemDraft:
    """Lightweight placeholder for LOW-confidence items (Q+2 and beyond)."""
    theme_id: str
    title: str
    quarter: str
    tshirt_size: str       # "XS" | "S" | "M" | "L" | "XL"
    confidence: Confidence = Confidence.LOW
    notes: str = ""

    @property
    def estimated_person_weeks(self) -> float:
        return float(TSHIRT_TO_PW.get(self.tshirt_size, 6))

def roadmap_to_markdown(roadmap: MultiQuarterRoadmap, quarters: list[str]) -> str:
    theme_by_id = {t.theme_id: t for t in roadmap.themes}
    lines = [f"# {roadmap.programme} — {roadmap.planning_year} Roadmap", ""]
    for quarter in quarters:
        lines.append(f"## {quarter}")
        items = roadmap.items_for_quarter(quarter)
        if not items:
            lines.append("_No items planned._")
        else:
            for item in sorted(items, key=lambda i: i.theme_id):
                theme = theme_by_id.get(item.theme_id)
                theme_label = theme.name if theme else item.theme_id
                conf = item.confidence.value.upper()
                lines.append(
                    f"- **[{theme_label}]** {item.title} "
                    f"({item.estimated_person_weeks:.0f} PW, {conf})"
                )
                if item.delivery_milestone:
                    lines.append(f"  _Milestone: {item.delivery_milestone}_")
        lines.append("")
    return "\n".join(lines)

@dataclass
class AnnualRetrospectiveMetrics:
    year: int
    total_items_planned_high: int
    total_items_delivered: int
    total_items_slipped: int
    total_items_cancelled: int
    surprise_pw: float            # person-weeks on unplanned items
    total_pw: float

    @property
    def delivery_rate(self) -> float:
        return self.total_items_delivered / self.total_items_planned_high if self.total_items_planned_high else 0.0

    @property
    def surprise_fraction(self) -> float:
        return self.surprise_pw / self.total_pw if self.total_pw else 0.0

    def summary(self) -> str:
        return (
            f"{self.year} Roadmap Retrospective:\n"
            f"  Delivery rate: {self.delivery_rate*100:.0f}% "
            f"({self.total_items_delivered}/{self.total_items_planned_high} HIGH items)\n"
            f"  Slipped items: {self.total_items_slipped}\n"
            f"  Cancelled items: {self.total_items_cancelled}\n"
            f"  Surprise work fraction: {self.surprise_fraction*100:.0f}% of total PW"
        )
